[TestMethod]
public void CalculateShipping_ZeroWeight_Throws()
{
    var calc = new DiscountCalculator();
    Assert.ThrowsException<ArgumentOutOfRangeException>(
        () => calc.CalculateShipping(50m, 0, false));
}

[TestMethod]
public void CalculateShipping_NegativeTotal_Throws()
{
    var calc = new DiscountCalculator();
    Assert.ThrowsException<ArgumentOutOfRangeException>(
        () => calc.CalculateShipping(-1m, 2.0, false));
}

// Boundary: exactly 250 should NOT get free shipping (> 250, not >= 250)
[TestMethod]
public void CalculateShipping_Exactly250_ChargesShipping()
{
    var calc = new DiscountCalculator();
    var cost = calc.CalculateShipping(250m, 2.0, false);
    Assert.AreNotEqual(0m, cost);
}

[TestMethod]
public void CalculateShipping_JustAbove250_FreeShipping()
{
    var calc = new DiscountCalculator();
    Assert.AreEqual(0m, calc.CalculateShipping(250.01m, 2.0, false));
}

// Heavy item fee boundary at 10kg
[TestMethod]
public void CalculateShipping_Exactly10kg_NoHeavyFee()
{
    var calc = new DiscountCalculator();
    // baseCost = 5 + 10*0.50 = 10.00, no heavy fee
    Assert.AreEqual(10.00m, calc.CalculateShipping(50m, 10.0, false));
}

[TestMethod]
public void CalculateShipping_Over10kg_IncludesHeavyFee()
{
    var calc = new DiscountCalculator();
    // baseCost = 5 + 11*0.50 = 10.50 + 15 = 25.50
    Assert.AreEqual(25.50m, calc.CalculateShipping(50m, 11.0, false));
}

// Express surcharge
[TestMethod]
public void CalculateShipping_Express_Adds50PercentSurcharge()
{
    var calc = new DiscountCalculator();
    // baseCost = 5 + 2*0.50 = 6.00, express = 6.00 * 1.50 = 9.00
    Assert.AreEqual(9.00m, calc.CalculateShipping(50m, 2.0, true));
}

[TestMethod]
public void CalculateShipping_HeavyAndExpress_BothApplied()
{
    var calc = new DiscountCalculator();
    // baseCost = 5 + 11*0.50 = 10.50 + 15 = 25.50, express = 25.50 * 1.50 = 38.25
    Assert.AreEqual(38.25m, calc.CalculateShipping(50m, 11.0, true));
}

// -- ApplyCoupon tests --

